    def get_otpauth_uri(self, secret, account_name, issuer_name="MyMFA", image_path=None):
        """
        Generates an otpauth URI for use with authenticator apps.
        """
        params = {
            'secret': secret,
            'issuer': issuer_name,
            'period': str(self.interval),
            'digits': str(self.digits),
            'algorithm': self.algorithm.upper(),
        }

        # RFC 6238 recommends that the label be 'issuer:account_name'
        # Google Authenticator and Authy often parse 'issuer' separately.
        label = f"{quote(issuer_name)}:{quote(account_name)}"
        uri = f"otpauth://totp/{label}?{urlencode(params)}"
        return uri

    def generate_qr_code(self, uri, filename="totp_qr_code.png"):
        """
        Generates a QR code image from an otpauth URI.
        """
        qr = qrcode.QRCode(
            version=1,
            error_correction=qrcode.constants.ERROR_CORRECT_L,
            box_size=10,
            border=4,
        )
        qr.add_data(uri)
        qr.make(fit=True)

        img = qr.make_image(fill_color="black", back_color="white")
        img.save(filename)
        return filename

